import React, { useState } from "react";

// Screens
import HomeScreen from "./screens/HomeScreen";
import DepositScreen from "./screens/DepositScreen";
import WithdrawScreen from "./screens/WithdrawScreen";
import TransactionHistoryScreen from "./screens/TransactionHistoryScreen";
import TransactionReceiptScreen from "./screens/TransactionReceiptScreen";
import AddMoneyOptionsScreen from "./AddMoneyOptionsScreen";
import PaymentProcessingScreen from "./PaymentProcessingScreen";
import PaymentSuccessScreen from "./PaymentSuccessScreen";

export default function App() {
  const [view, setView] = useState("Home");
  const [balance, setBalance] = useState(5000);
  const [savingsBalance, setSavingsBalance] = useState(2000);
  const [transactions, setTransactions] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);
  const [userName, setUserName] = useState("Pips");

  // Helper to add a transaction
  const addTransaction = (tx) => {
    setTransactions([tx, ...transactions]);
    if (tx.type.toLowerCase().includes("deposit")) setBalance(balance + tx.amount);
    if (tx.type.toLowerCase().includes("withdraw")) setBalance(balance - tx.amount);
  };

  const openScreen = (screen) => {
    switch (screen) {
      case "Deposit":
        setView("Deposit");
        break;
      case "Withdraw":
        setView("Withdraw");
        break;
      case "Transactions":
        setView("Transactions");
        break;
      case "TransactionReceipt":
        setView("TransactionReceipt");
        break;
      case "AddMoneyOptions":
        setView("AddMoneyOptions");
        break;
      case "PaymentProcessing":
        setView("PaymentProcessing");
        break;
      case "PaymentSuccess":
        setView("PaymentSuccess");
        break;
      case "SavingsDeposit":
        setView("SavingsDeposit");
        break;
      case "SavingsWithdraw":
        setView("SavingsWithdraw");
        break;
      default:
        setView("Home");
    }
  };

  // Deposit handler
  const handleDeposit = (amount) => {
    const tx = {
      id: Date.now(),
      type: "Deposit",
      title: "Deposit",
      amount,
      date: new Date().toLocaleString(),
      reference: `DEP${Math.floor(Math.random() * 1000000)}`,
    };
    addTransaction(tx);
    setSelectedTransaction(tx);
    setView("TransactionReceipt");
  };

  // Withdraw handler
  const handleWithdraw = (amount) => {
    const tx = {
      id: Date.now(),
      type: "Withdraw",
      title: "Withdrawal",
      amount,
      date: new Date().toLocaleString(),
      reference: `WTH${Math.floor(Math.random() * 1000000)}`,
    };
    addTransaction(tx);
    setSelectedTransaction(tx);
    setView("TransactionReceipt");
  };

  // Render screens
  switch (view) {
    case "Deposit":
      return <DepositScreen onDeposit={handleDeposit} onBack={() => setView("Home")} />;

    case "Withdraw":
      return <WithdrawScreen balance={balance} onWithdraw={handleWithdraw} onBack={() => setView("Home")} />;

    case "Transactions":
      return <TransactionHistoryScreen
        transactions={transactions}
        onSelectTransaction={(tx) => { setSelectedTransaction(tx); setView("TransactionReceipt"); }}
        onBack={() => setView("Home")}
      />;

    case "TransactionReceipt":
      return <TransactionReceiptScreen transaction={selectedTransaction} onBack={() => setView("Home")} />;

    case "AddMoneyOptions":
      return <AddMoneyOptionsScreen
        onBack={() => setView("Home")}
        onSelectOption={() => setView("PaymentProcessing")}
      />;

    case "PaymentProcessing":
      return <PaymentProcessingScreen onBack={() => setView("Home")} />;

    case "PaymentSuccess":
      return <PaymentSuccessScreen
        transaction={selectedTransaction || { amount: 0, reference: "N/A" }}
        onBack={() => setView("Home")}
      />;

    default:
      return (
        <HomeScreen
          balance={balance}
          savingsBalance={savingsBalance}
          transactions={transactions}
          userName={userName}
          openScreen={openScreen}
        />
      );
  }
}
